"""Build the Macedonian graduation-thesis document for ApexInsight.

This wrapper reuses the carefully sourced platform/ML narrative and makes the
deliverable presentation-ready: experiment figures are embedded from immutable
artifacts, while interface illustrations remain explicit screenshot placeholders
for the author to replace with current application captures.
"""

from __future__ import annotations

from pathlib import Path

from docx import Document
from docx.enum.text import WD_ALIGN_PARAGRAPH
from docx.oxml import OxmlElement
from docx.oxml.ns import qn
from docx.shared import Inches, Pt, RGBColor
from docx.text.paragraph import Paragraph
from PIL import Image

